--
-- Table structure for table `envios`
--

DROP TABLE IF EXISTS `envios`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `envios` (
  `id_envio` int NOT NULL AUTO_INCREMENT,
  `id_remitente` int NOT NULL,
  `id_destinatario` int NOT NULL,
  `id_ruta` int NOT NULL,
  `tipo_envio` enum('Express','Estándar','Carga Pesada','Frágil') NOT NULL,
  `peso` decimal(10,2) NOT NULL,
  `fecha_envio` date NOT NULL,
  `fecha_entrega` date DEFAULT NULL,
  `estado` enum('Pendiente','Recogido','En Centro Logístico','En Tránsito','En Reparto','Entregado') NOT NULL,
  `tiempo_entrega` int DEFAULT NULL,
  `costo_envio` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id_envio`),
  KEY `fk_envio_remitente` (`id_remitente`),
  KEY `fk_envio_destinatario` (`id_destinatario`),
  KEY `fk_envio_ruta` (`id_ruta`),
  CONSTRAINT `fk_envio_destinatario` FOREIGN KEY (`id_destinatario`) REFERENCES `clientes` (`id_cliente`),
  CONSTRAINT `fk_envio_remitente` FOREIGN KEY (`id_remitente`) REFERENCES `clientes` (`id_cliente`),
  CONSTRAINT `fk_envio_ruta` FOREIGN KEY (`id_ruta`) REFERENCES `rutas` (`id_ruta`)
) ENGINE=InnoDB AUTO_INCREMENT=5001 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

